class Solution:
    def longestString(self, x: int, y: int, z: int) -> int:
        max_len = 0
        # Try all possible combinations of AA, BB, AB
        from itertools import permutations

        # Generate all possible combinations of AA, BB, AB with their counts
        strings = []
        for _ in range(x):
            strings.append("AA")
        for _ in range(y):
            strings.append("BB")
        for _ in range(z):
            strings.append("AB")

        # Try all permutations of the strings
        from itertools import permutations

        for perm in permutations(strings):
            s = ''.join(perm)
            if 'AAA' not in s and 'BBB' not in s:
                max_len = max(max_len, len(s))

        return max_len
